10	/// Check if an idempotency key has already been used.
11	/// Returns `Some(HttpResponse)` with the cached response if found, `None` if new.
12	pub fn check_idempotency(
13	    key: Uuid,
14	    conn: &mut PgConnection,
15	) -> Result<Option<HttpResponse>, AppError> {
16	    let record: Option<IdempotencyRecord> = idempotency_keys::table
17	        .find(key)
18	        .select(IdempotencyRecord::as_select())
19	        .first(conn)
20	        .optional()?;
21	
22	    match record {
23	        Some(rec) => {
24	            if rec.expires_at < Utc::now() {
25	                // Expired — treat as new
26	                diesel::delete(idempotency_keys::table.find(key)).execute(conn)?;
27	                Ok(None)
28	            } else {
29	                // Return cached response
30	                let status =
31	                    actix_web::http::StatusCode::from_u16(rec.response_status as u16)
32	                        .unwrap_or(actix_web::http::StatusCode::OK);
33	                Ok(Some(HttpResponse::build(status).json(rec.response_body)))
34	            }
35	        }
36	        None => Ok(None),
37	    }
38	}
