40	/// Atomically reserve an idempotency key inside a DB transaction.
41	/// Uses INSERT with PK constraint to prevent concurrent duplicate mutations.
42	/// Returns Ok(None) if reserved (proceed with mutation).
43	/// Returns Ok(Some(response)) if already completed (replay cached).
44	pub fn reserve_idempotency_key(
45	    key: Uuid,
46	    resource_type: &str,
47	    conn: &mut PgConnection,
48	) -> Result<Option<HttpResponse>, AppError> {
49	    // Check for existing completed record first
50	    let existing: Option<IdempotencyRecord> = idempotency_keys::table
51	        .find(key)
52	        .select(IdempotencyRecord::as_select())
53	        .first(conn)
54	        .optional()?;
55	
56	    if let Some(rec) = existing {
57	        if rec.expires_at < Utc::now() {
58	            diesel::delete(idempotency_keys::table.find(key)).execute(conn)?;
59	        } else if rec.response_status > 0 {
60	            let status = actix_web::http::StatusCode::from_u16(rec.response_status as u16)
61	                .unwrap_or(actix_web::http::StatusCode::OK);
62	            return Ok(Some(HttpResponse::build(status).json(rec.response_body)));
63	        } else {
64	            // Sentinel 0 = another transaction in progress
65	            return Err(AppError::Conflict(
66	                "Duplicate request in progress for this idempotency key".into(),
67	            ));
68	        }
69	    }
70	
71	    // Reserve atomically via PK insert (sentinel status=0)
72	    let placeholder = NewIdempotencyRecord {
73	        key,
74	        resource_type: resource_type.to_string(),
75	        resource_id: Uuid::nil(),
76	        response_status: 0,
77	        response_body: serde_json::json!(null),
78	    };
79	
80	    let inserted = diesel::insert_into(idempotency_keys::table)
81	        .values(&placeholder)
82	        .on_conflict_do_nothing()
83	        .execute(conn)?;
84	
85	    if inserted == 0 {
86	        // Lost race — another tx inserted first
87	        return Err(AppError::Conflict(
88	            "Duplicate request for this idempotency key".into(),
89	        ));
90	    }
91	
92	    Ok(None)
93	}
