95	/// Finalize a reserved idempotency key with actual response after mutation.
96	pub fn finalize_idempotency(
97	    key: Uuid,
98	    resource_id: Uuid,
99	    status: i16,
100	    body: &serde_json::Value,
101	    conn: &mut PgConnection,
102	) -> Result<(), AppError> {
103	    diesel::update(idempotency_keys::table.find(key))
104	        .set((
105	            idempotency_keys::resource_id.eq(resource_id),
106	            idempotency_keys::response_status.eq(status),
107	            idempotency_keys::response_body.eq(body),
108	        ))
109	        .execute(conn)?;
110	    Ok(())
111	}
112	
113	/// Store idempotency response (upsert). Used for paths where
114	/// reservation + finalization is not yet adopted.
115	pub fn store_idempotency(
116	    key: Uuid,
117	    resource_type: &str,
118	    resource_id: Uuid,
119	    status: i16,
120	    body: &serde_json::Value,
121	    conn: &mut PgConnection,
122	) -> Result<(), AppError> {
123	    let new_record = NewIdempotencyRecord {
124	        key,
125	        resource_type: resource_type.to_string(),
126	        resource_id,
127	        response_status: status,
128	        response_body: body.clone(),
129	    };
130	
131	    diesel::insert_into(idempotency_keys::table)
132	        .values(&new_record)
133	        .on_conflict(idempotency_keys::key)
134	        .do_update()
135	        .set((
136	            idempotency_keys::resource_id.eq(resource_id),
137	            idempotency_keys::response_status.eq(status),
138	            idempotency_keys::response_body.eq(body),
139	        ))
140	        .execute(conn)?;
141	
142	    Ok(())
143	}
