9	/// Record an audit entry for a write operation.
10	pub fn record(
11	    conn: &mut PgConnection,
12	    user_id: Option<Uuid>,
13	    action: &str,
14	    resource_type: &str,
15	    resource_id: Option<Uuid>,
16	    http_method: &str,
17	    http_path: &str,
18	    before_state: Option<&[u8]>,
19	    after_state: Option<&[u8]>,
20	    metadata: Option<serde_json::Value>,
21	    ip_address: Option<String>,
22	) -> Result<(), AppError> {
23	    let entry = NewAuditEntry {
24	        user_id,
25	        action: action.to_string(),
26	        resource_type: resource_type.to_string(),
27	        resource_id,
28	        http_method: http_method.to_string(),
29	        http_path: http_path.to_string(),
30	        before_hash: before_state.map(|d| hash_sha256(d)),
31	        after_hash: after_state.map(|d| hash_sha256(d)),
32	        metadata,
33	        ip_address,
34	    };
35	
36	    diesel::insert_into(audit_log::table)
37	        .values(&entry)
38	        .execute(conn)?;
39	
40	    Ok(())
41	}
