43	/// Convenience wrapper for handler-level audit with before/after state.
44	/// Accepts serializable before/after values, canonically serializes them,
45	/// and records the audit entry. Sensitive fields must be excluded by the
46	/// caller before passing values here.
47	pub fn audit_write(
48	    conn: &mut PgConnection,
49	    user_id: Uuid,
50	    action: &str,
51	    resource_type: &str,
52	    resource_id: Option<Uuid>,
53	    before: Option<&serde_json::Value>,
54	    after: Option<&serde_json::Value>,
55	) -> Result<(), AppError> {
56	    let before_bytes = before.map(|v| canonical_bytes(v));
57	    let after_bytes = after.map(|v| canonical_bytes(v));
58	
59	    record(
60	        conn,
61	        Some(user_id),
62	        action,
63	        resource_type,
64	        resource_id,
65	        match action {
66	            "create" => "POST",
67	            "update" => "PUT",
68	            "delete" => "DELETE",
69	            _ => "POST",
70	        },
71	        &format!("/api/v1/{}", resource_type),
72	        before_bytes.as_deref(),
73	        after_bytes.as_deref(),
74	        None,
75	        None,
76	    )
77	}
78	
79	/// Deterministic canonical serialization for hashing.
80	/// Uses serde_json with sorted keys (default behavior).
81	fn canonical_bytes(value: &serde_json::Value) -> Vec<u8> {
82	    serde_json::to_vec(value).unwrap_or_default()
83	}
84	
85	/// Compute SHA-256 hash of arbitrary bytes, returned as hex string.
86	pub fn hash_sha256(data: &[u8]) -> String {
87	    let mut hasher = Sha256::new();
88	    hasher.update(data);
89	    format!("{:x}", hasher.finalize())
90	}
