42	pub async fn initiate_return(
43	    pool: web::Data<DbPool>,
44	    auth: AuthenticatedUser,
45	    req: HttpRequest,
46	    path: web::Path<Uuid>,
47	    body: web::Json<InitiateReturnRequest>,
48	) -> Result<HttpResponse, AppError> {
49	    let source_order_id = path.into_inner();
50	    let mut conn = pool.get().map_err(crate::errors::pool_err)?;
51	    let ctx = check_permission_for_request(&auth.0, "order.return", req.method().as_str(), req.path(), &mut conn)?;
52	
53	    // Atomic idempotency: check for cached replay first
54	    if let Some(cached) = check_idempotency(body.idempotency_key, &mut conn)? {
55	        return Ok(cached);
56	    }
57	
58	    let source: Order = orders::table
59	        .find(source_order_id)
60	        .select(Order::as_select())
61	        .first(&mut conn)?;
62	
63	    // Object-level scope enforcement
64	    ctx.enforce_scope(source.cashier_user_id, source.department.as_deref(), Some(&source.location))?;
65	
66	    if source.status != OrderStatus::Paid && source.status != OrderStatus::Closed {
67	        return Err(AppError::Validation(
68	            "Returns can only be initiated on Paid or Closed orders".into(),
69	        ));
70	    }
71	
72	    let result = conn.transaction::<_, AppError, _>(|conn| {
73	        // Reserve idempotency key atomically inside transaction
74	        if let Some(_cached) = reserve_idempotency_key(body.idempotency_key, "return_order", conn)? {
75	            return Err(AppError::Internal("idempotency_race".into()));
76	        }
77	        // Validate return line items against originals
78	        let mut return_subtotal: i64 = 0;
79	        let mut return_tax: i64 = 0;
80	        let mut new_line_items = Vec::new();
81	
82	        for rli in &body.line_items {
83	            if rli.quantity <= 0 {
84	                return Err(AppError::Validation("Return quantity must be positive".into()));
85	            }
86	
87	            let original: OrderLineItem = order_line_items::table
88	                .find(rli.original_line_item_id)
89	                .select(OrderLineItem::as_select())
90	                .first(conn)?;
91	
92	            if original.order_id != source_order_id {
93	                return Err(AppError::Validation(
94	                    "Line item does not belong to the source order".into(),
95	                ));
96	            }
97	
98	            if rli.quantity > original.quantity {
99	                return Err(AppError::Validation(format!(
100	                    "Return quantity {} exceeds original quantity {} for SKU {}",
101	                    rli.quantity, original.quantity, original.sku
102	                )));
103	            }
104	
105	            let line_total = -(original.unit_price_cents * rli.quantity as i64);
106	            let line_tax = -(original.tax_cents * rli.quantity as i64);
107	            return_subtotal += line_total;
108	            return_tax += line_tax;
109	
110	            new_line_items.push(NewOrderLineItem {
111	                order_id: Uuid::nil(), // placeholder, set after order insert
112	                sku: original.sku.clone(),
113	                description: original.description.clone(),
114	                quantity: -(rli.quantity),
115	                unit_price_cents: original.unit_price_cents,
116	                tax_cents: original.tax_cents,
117	                line_total_cents: line_total,
118	                original_line_item_id: Some(original.id),
119	            });
120	        }
121	
122	        let return_total = return_subtotal + return_tax;
123	
124	        // Generate return order number
125	        let count: i64 = orders::table
126	            .filter(orders::original_order_id.eq(source_order_id))
127	            .count()
128	            .get_result(conn)?;
129	        let return_number = format!("{}-R{}", source.order_number, count + 1);
130	
131	        let new_order = NewOrder {
132	            order_number: return_number,
133	            status: OrderStatus::ReturnInitiated,
134	            cashier_user_id: auth.0.sub,
135	            location: source.location.clone(),
136	            department: source.department.clone(),
137	            customer_reference: source.customer_reference.clone(),
138	            original_order_id: Some(source_order_id),
139	            subtotal_cents: return_subtotal,
140	            tax_cents: return_tax,
141	            total_cents: return_total,
142	            notes: body.notes.clone(),
143	        };
144	
145	        let return_order: Order = diesel::insert_into(orders::table)
146	            .values(&new_order)
147	            .get_result(conn)?;
148	
149	        // Insert return line items
150	        let mut items = Vec::new();
151	        for mut nli in new_line_items {
152	            nli.order_id = return_order.id;
153	            let item: OrderLineItem = diesel::insert_into(order_line_items::table)
154	                .values(&nli)
155	                .get_result(conn)?;
156	            items.push(item);
157	        }
158	
159	        // Transition source order
160	        diesel::update(orders::table.find(source_order_id))
161	            .set((
162	                orders::status.eq(OrderStatus::ReturnInitiated),
163	                orders::updated_at.eq(Utc::now()),
164	            ))
165	            .execute(conn)?;
166	
167	        Ok(OrderDetailResponse {
168	            order: OrderResponse::from(return_order),
169	            line_items: items.into_iter().map(OrderLineItemResponse::from).collect(),
170	            ledger_entries: vec![],
171	        })
172	    })?;
173	
174	    let json =
175	        serde_json::to_value(&result).map_err(|e| AppError::Internal(e.to_string()))?;
176	    finalize_idempotency(body.idempotency_key, result.order.id, 201, &json, &mut conn)?;
177	
178	    Ok(HttpResponse::Created().json(result))
179	}
