189	pub async fn initiate_exchange(
190	    pool: web::Data<DbPool>,
191	    auth: AuthenticatedUser,
192	    req: HttpRequest,
193	    path: web::Path<Uuid>,
194	    body: web::Json<InitiateExchangeRequest>,
195	) -> Result<HttpResponse, AppError> {
196	    let source_order_id = path.into_inner();
197	    let mut conn = pool.get().map_err(crate::errors::pool_err)?;
198	    let ctx = check_permission_for_request(&auth.0, "order.exchange", req.method().as_str(), req.path(), &mut conn)?;
199	
200	    // Atomic idempotency: check for cached replay
201	    if let Some(cached) = check_idempotency(body.idempotency_key, &mut conn)? {
202	        return Ok(cached);
203	    }
204	
205	    let source: Order = orders::table
206	        .find(source_order_id)
207	        .select(Order::as_select())
208	        .first(&mut conn)?;
209	
210	    ctx.enforce_scope(source.cashier_user_id, source.department.as_deref(), Some(&source.location))?;
211	
212	    if source.status != OrderStatus::Paid && source.status != OrderStatus::Closed {
213	        return Err(AppError::Validation(
214	            "Exchanges can only be initiated on Paid or Closed orders".into(),
215	        ));
216	    }
217	
218	    let result = conn.transaction::<_, AppError, _>(|conn| {
219	        // Reserve idempotency key atomically inside transaction
220	        if let Some(_cached) = reserve_idempotency_key(body.idempotency_key, "exchange_order", conn)? {
221	            return Err(AppError::Internal("idempotency_race".into()));
222	        }
223	        // --- Return portion ---
224	        let mut return_subtotal: i64 = 0;
225	        let mut return_tax: i64 = 0;
226	        let mut return_line_items = Vec::new();
227	
228	        for rli in &body.return_items {
229	            let original: OrderLineItem = order_line_items::table
230	                .find(rli.original_line_item_id)
231	                .select(OrderLineItem::as_select())
232	                .first(conn)?;
233	
234	            if original.order_id != source_order_id {
235	                return Err(AppError::Validation(
236	                    "Line item does not belong to the source order".into(),
237	                ));
238	            }
239	
240	            let line_total = -(original.unit_price_cents * rli.quantity as i64);
241	            let line_tax = -(original.tax_cents * rli.quantity as i64);
242	            return_subtotal += line_total;
243	            return_tax += line_tax;
244	
245	            return_line_items.push(NewOrderLineItem {
246	                order_id: Uuid::nil(),
247	                sku: original.sku.clone(),
248	                description: original.description.clone(),
249	                quantity: -(rli.quantity),
250	                unit_price_cents: original.unit_price_cents,
251	                tax_cents: original.tax_cents,
252	                line_total_cents: line_total,
253	                original_line_item_id: Some(original.id),
254	            });
255	        }
256	
257	        // --- New items portion ---
258	        let mut new_subtotal: i64 = 0;
259	        let mut new_tax: i64 = 0;
260	        let mut exchange_line_items = Vec::new();
261	
262	        for li in &body.new_items {
263	            let line_total = li.unit_price_cents * li.quantity as i64;
264	            new_subtotal += line_total;
265	            new_tax += li.tax_cents * li.quantity as i64;
266	
267	            exchange_line_items.push(NewOrderLineItem {
268	                order_id: Uuid::nil(),
269	                sku: li.sku.clone(),
270	                description: li.description.clone(),
271	                quantity: li.quantity,
272	                unit_price_cents: li.unit_price_cents,
273	                tax_cents: li.tax_cents,
274	                line_total_cents: line_total,
275	                original_line_item_id: None,
276	            });
277	        }
278	
279	        // Create exchange order combining return + new items
280	        let net_subtotal = return_subtotal + new_subtotal;
281	        let net_tax = return_tax + new_tax;
282	        let net_total = net_subtotal + net_tax;
283	
284	        let count: i64 = orders::table
285	            .filter(orders::original_order_id.eq(source_order_id))
286	            .count()
287	            .get_result(conn)?;
288	        let exchange_number = format!("{}-X{}", source.order_number, count + 1);
289	
290	        let new_order = NewOrder {
291	            order_number: exchange_number,
292	            status: OrderStatus::Draft,
293	            cashier_user_id: auth.0.sub,
294	            location: source.location.clone(),
295	            department: source.department.clone(),
296	            customer_reference: source.customer_reference.clone(),
297	            original_order_id: Some(source_order_id),
298	            subtotal_cents: net_subtotal,
299	            tax_cents: net_tax,
300	            total_cents: net_total,
301	            notes: body.notes.clone(),
302	        };
303	
304	        let exchange_order: Order = diesel::insert_into(orders::table)
305	            .values(&new_order)
306	            .get_result(conn)?;
307	
308	        let mut all_items = Vec::new();
309	        for mut nli in return_line_items {
310	            nli.order_id = exchange_order.id;
311	            let item: OrderLineItem = diesel::insert_into(order_line_items::table)
312	                .values(&nli)
313	                .get_result(conn)?;
314	            all_items.push(item);
315	        }
316	        for mut nli in exchange_line_items {
317	            nli.order_id = exchange_order.id;
318	            let item: OrderLineItem = diesel::insert_into(order_line_items::table)
319	                .values(&nli)
320	                .get_result(conn)?;
321	            all_items.push(item);
322	        }
323	
324	        Ok(OrderDetailResponse {
325	            order: OrderResponse::from(exchange_order),
326	            line_items: all_items.into_iter().map(OrderLineItemResponse::from).collect(),
327	            ledger_entries: vec![],
328	        })
329	    })?;
330	
331	    let json =
332	        serde_json::to_value(&result).map_err(|e| AppError::Internal(e.to_string()))?;
333	    finalize_idempotency(body.idempotency_key, result.order.id, 201, &json, &mut conn)?;
334	
335	    Ok(HttpResponse::Created().json(result))
336	}
