344	/// Initiate a reversal — creates an approval request but does NOT mutate
345	/// financial state. The actual reversal executes only after approval.
346	pub async fn initiate_reversal(
347	    pool: web::Data<DbPool>,
348	    auth: AuthenticatedUser,
349	    req: HttpRequest,
350	    path: web::Path<Uuid>,
351	    body: web::Json<InitiateReversalRequest>,
352	) -> Result<HttpResponse, AppError> {
353	    let order_id = path.into_inner();
354	    let mut conn = pool.get().map_err(crate::errors::pool_err)?;
355	
356	    // Atomic idempotency: check for cached replay
357	    if let Some(cached) = check_idempotency(body.idempotency_key, &mut conn)? {
358	        return Ok(cached);
359	    }
360	    // Reserve key atomically before any mutation
361	    if let Some(_cached) = reserve_idempotency_key(body.idempotency_key, "reversal_request", &mut conn)? {
362	        return Err(AppError::Conflict("Duplicate reversal request in progress".into()));
363	    }
364	
365	    let order: Order = orders::table
366	        .find(order_id)
367	        .select(Order::as_select())
368	        .first(&mut conn)?;
369	
370	    // Object-level scope enforcement on target order
371	    let scope_ctx = check_permission_no_approval(&auth.0, "order.read", &mut conn)?;
372	    scope_ctx.enforce_scope(order.cashier_user_id, order.department.as_deref(), Some(&order.location))?;
373	
374	    if order.status != OrderStatus::Paid && order.status != OrderStatus::Closed {
375	        return Err(AppError::Validation(
376	            "Reversals can only be initiated on Paid or Closed orders".into(),
377	        ));
378	    }
379	
380	    // Determine which permission applies
381	    let is_late = order.created_at < Utc::now() - Duration::hours(24);
382	    let perm_code = if is_late { "order.reverse_late" } else { "order.reverse" };
383	    check_permission_no_approval(&auth.0, perm_code, &mut conn)?;
384	
385	    // Create approval request — NO financial mutation yet
386	    let perm_id = resolve_permission_id(perm_code, &mut conn)?;
387	    let payload = serde_json::json!({
388	        "type": "order_reversal",
389	        "order_id": order_id,
390	        "order_number": order.order_number,
391	        "idempotency_key": body.idempotency_key,
392	        "is_late_reversal": is_late,
393	        "note": body.notes,
394	        "requested_by": auth.0.sub,
395	    });
396	
397	    let approval: ApprovalRequest = diesel::insert_into(approval_requests::table)
398	        .values(&NewApprovalRequest {
399	            permission_point_id: perm_id,
400	            requester_user_id: auth.0.sub,
401	            payload,
402	        })
403	        .returning(ApprovalRequest::as_returning())
404	        .get_result(&mut conn)?;
405	
406	    // Mark order as ReversalPending (no ledger changes)
407	    diesel::update(orders::table.find(order_id))
408	        .set((
409	            orders::status.eq(OrderStatus::ReversalPending),
410	            orders::notes.eq(body.notes.as_deref()),
411	            orders::updated_at.eq(Utc::now()),
412	        ))
413	        .execute(&mut conn)?;
414	
415	    let response = serde_json::json!({
416	        "message": "Reversal requires approval before financial mutation",
417	        "approval_request_id": approval.id,
418	        "order_id": order_id,
419	        "status": "reversal_pending",
420	    });
421	
422	    let json = serde_json::to_value(&response).unwrap();
423	    finalize_idempotency(body.idempotency_key, order_id, 202, &json, &mut conn)?;
424	
425	    Ok(HttpResponse::Accepted().json(response))
426	}
