434	/// Execute a reversal ONLY after the linked approval is Approved.
435	/// This is where financial mutation (ledger entries) actually happens.
436	pub async fn execute_reversal(
437	    pool: web::Data<DbPool>,
438	    auth: AuthenticatedUser,
439	    req: HttpRequest,
440	    path: web::Path<Uuid>,
441	    body: web::Json<ExecuteReversalRequest>,
442	) -> Result<HttpResponse, AppError> {
443	    let order_id = path.into_inner();
444	    let mut conn = pool.get().map_err(crate::errors::pool_err)?;
445	
446	    // Atomic idempotency: check for cached replay
447	    if let Some(cached) = check_idempotency(body.idempotency_key, &mut conn)? {
448	        return Ok(cached);
449	    }
450	
451	    let rev_ctx = check_permission_no_approval(&auth.0, "order.reverse", &mut conn)?;
452	
453	    // Verify approval is Approved
454	    let approval: ApprovalRequest = approval_requests::table
455	        .find(body.approval_request_id)
456	        .select(ApprovalRequest::as_select())
457	        .first(&mut conn)
458	        .map_err(|_| AppError::NotFound("Approval request not found".into()))?;
459	
460	    if approval.status != ApprovalStatus::Approved {
461	        return Err(AppError::Validation(
462	            "Reversal cannot execute: approval not yet approved".into(),
463	        ));
464	    }
465	
466	    // Verify the approval is for this order
467	    let approval_order_id = approval.payload["order_id"]
468	        .as_str()
469	        .and_then(|s| s.parse::<Uuid>().ok());
470	    if approval_order_id != Some(order_id) {
471	        return Err(AppError::Validation(
472	            "Approval request does not match this order".into(),
473	        ));
474	    }
475	
476	    let order: Order = orders::table
477	        .find(order_id)
478	        .select(Order::as_select())
479	        .first(&mut conn)?;
480	
481	    // Object-level scope enforcement
482	    rev_ctx.enforce_scope(order.cashier_user_id, order.department.as_deref(), Some(&order.location))?;
483	
484	    if order.status != OrderStatus::ReversalPending {
485	        return Err(AppError::Validation(
486	            "Order must be in ReversalPending status to execute reversal".into(),
487	        ));
488	    }
489	
490	    // Capture before-state for audit
491	    let before = serde_json::json!({"order_id": order_id, "status": "reversal_pending", "total_cents": order.total_cents});
492	
493	    // NOW perform the financial mutation inside a transaction
494	    let reversal_entries = conn.transaction::<_, AppError, _>(|conn| {
495	        // Reserve idempotency key atomically inside transaction
496	        if let Some(_cached) = reserve_idempotency_key(body.idempotency_key, "reversal_executed", conn)? {
497	            return Err(AppError::Internal("idempotency_race".into()));
498	        }
499	
500	        let original_entries: Vec<LedgerEntry> = ledger_entries::table
501	            .filter(ledger_entries::order_id.eq(order_id))
502	            .filter(ledger_entries::entry_kind.eq(LedgerEntryKind::Payment))
503	            .select(LedgerEntry::as_select())
504	            .load(conn)?;
505	
506	        let mut reversals = Vec::new();
507	        for entry in &original_entries {
508	            let reversal = NewLedgerEntry {
509	                order_id,
510	                tender_type: entry.tender_type.clone(),
511	                entry_kind: LedgerEntryKind::Reversal,
512	                amount_cents: -(entry.amount_cents),
513	                reference_code: Some(format!("REVERSAL-OF-{}", entry.id)),
514	                idempotency_key: Uuid::new_v4(),
515	                created_by: auth.0.sub,
516	            };
517	            let created: LedgerEntry = diesel::insert_into(ledger_entries::table)
518	                .values(&reversal)
519	                .get_result(conn)?;
520	            reversals.push(created);
521	        }
522	
523	        diesel::update(orders::table.find(order_id))
524	            .set((
525	                orders::status.eq(OrderStatus::Reversed),
526	                orders::updated_at.eq(Utc::now()),
527	            ))
528	            .execute(conn)?;
529	
530	        Ok(reversals)
531	    })?;
532	
533	    // Audit the financial mutation with before/after state
534	    let after = serde_json::json!({"order_id": order_id, "status": "reversed", "reversal_count": reversal_entries.len()});
535	    let _ = crate::audit::service::audit_write(
536	        &mut conn, auth.0.sub, "reversal", "orders", Some(order_id), Some(&before), Some(&after),
537	    );
538	
539	    let updated: Order = orders::table.find(order_id).select(Order::as_select()).first(&mut conn)?;
540	    let items: Vec<OrderLineItem> = order_line_items::table
541	        .filter(order_line_items::order_id.eq(order_id))
542	        .select(OrderLineItem::as_select())
543	        .load(&mut conn)?;
544	
545	    let response = OrderDetailResponse {
546	        order: OrderResponse::from(updated),
547	        line_items: items.into_iter().map(OrderLineItemResponse::from).collect(),
548	        ledger_entries: reversal_entries.into_iter().map(LedgerEntryResponse::from).collect(),
549	    };
550	
551	    let json = serde_json::to_value(&response).map_err(|e| AppError::Internal(e.to_string()))?;
552	    finalize_idempotency(body.idempotency_key, order_id, 200, &json, &mut conn)?;
553	
554	    Ok(HttpResponse::Ok().json(response))
555	}
