48	pub async fn approve(
49	    pool: web::Data<DbPool>,
50	    auth: AuthenticatedUser,
51	    req: HttpRequest,
52	    path: web::Path<Uuid>,
53	) -> Result<HttpResponse, AppError> {
54	    let req_id = path.into_inner();
55	    let mut conn = pool.get().map_err(crate::errors::pool_err)?;
56	    let _ctx = check_permission_for_request(&auth.0, "approval.decide", req.method().as_str(), req.path(), &mut conn)?;
57	
58	    let approval: ApprovalRequest = approval_requests::table
59	        .find(req_id)
60	        .select(ApprovalRequest::as_select())
61	        .first(&mut conn)?;
62	
63	    if approval.status != ApprovalStatus::Pending {
64	        return Err(AppError::Validation("Approval request is not pending".into()));
65	    }
66	
67	    // Independent approver rule: requester cannot approve their own request
68	    if approval.requester_user_id == auth.0.sub {
69	        return Err(AppError::Forbidden(
70	            "Requester cannot approve their own request — independent approver required".into(),
71	        ));
72	    }
73	
74	    let policy: ApprovalPolicy = approval_policies::table
75	        .filter(approval_policies::permission_point_id.eq(approval.permission_point_id))
76	        .filter(approval_policies::approver_role_id.eq(auth.0.role_id))
77	        .first(&mut conn)
78	        .map_err(|_| {
79	            AppError::Forbidden("Your role is not an authorized approver for this action".into())
80	        })?;
81	
82	    let approver_id = auth.0.sub;
83	    if approval.approved_by.contains(&approver_id) {
84	        return Err(AppError::Validation("You have already approved this request".into()));
85	    }
86	
87	    let mut new_approved = approval.approved_by.clone();
88	    new_approved.push(approver_id);
89	
90	    let new_count = new_approved.len() as i32;
91	
92	    if new_count >= policy.min_approvers {
93	        diesel::update(approval_requests::table.find(req_id))
94	            .set((
95	                approval_requests::approved_by.eq(&new_approved),
96	                approval_requests::status.eq(ApprovalStatus::Approved),
97	                approval_requests::resolved_at.eq(Some(Utc::now())),
98	            ))
99	            .execute(&mut conn)?;
100	    } else {
101	        diesel::update(approval_requests::table.find(req_id))
102	            .set(approval_requests::approved_by.eq(&new_approved))
103	            .execute(&mut conn)?;
104	    }
105	
106	    let updated: ApprovalRequest = approval_requests::table
107	        .find(req_id)
108	        .select(ApprovalRequest::as_select())
109	        .first(&mut conn)?;
110	    Ok(HttpResponse::Ok().json(ApprovalRequestResponse::from(updated)))
111	}
