10	/// Standard permission check (layers 1-2 + approval gate).
11	/// Layer 3 (capability match) is skipped — use `check_permission_for_request`
12	/// when request method+path context is available.
13	pub fn check_permission(
14	    claims: &Claims,
15	    permission_code: &str,
16	    conn: &mut PgConnection,
17	) -> Result<PermissionContext, AppError> {
18	    let perm = resolve_layers_1_2(claims, permission_code, conn)?;
19	    if perm.requires_approval {
20	        return Err(AppError::Forbidden(
21	            format!("Permission {} requires approval workflow", permission_code),
22	        ));
23	    }
24	    Ok(build_context(claims, perm.id))
25	}
