27	/// Permission check without approval gate.
28	pub fn check_permission_no_approval(
29	    claims: &Claims,
30	    permission_code: &str,
31	    conn: &mut PgConnection,
32	) -> Result<PermissionContext, AppError> {
33	    let perm = resolve_layers_1_2(claims, permission_code, conn)?;
34	    Ok(build_context(claims, perm.id))
35	}
