37	/// Full three-layer RBAC check with request-aware capability enforcement.
38	///   Layer 1: permission_point lookup
39	///   Layer 2: role→permission binding (or delegation)
40	///   Layer 3: permission→api_capability matching on http_method + path_pattern
41	/// If no capabilities are registered for the permission, layer 3 is skipped.
42	pub fn check_permission_for_request(
43	    claims: &Claims,
44	    permission_code: &str,
45	    http_method: &str,
46	    http_path: &str,
47	    conn: &mut PgConnection,
48	) -> Result<PermissionContext, AppError> {
49	    let perm = resolve_layers_1_2(claims, permission_code, conn)?;
50	
51	    // Layer 3: capability enforcement
52	    let caps: Vec<crate::models::api_capability::ApiCapability> = api_capabilities::table
53	        .filter(api_capabilities::permission_point_id.eq(perm.id))
54	        .load(conn)
55	        .unwrap_or_default();
56	
57	    if !caps.is_empty() {
58	        let method_upper = http_method.to_uppercase();
59	        let matched = caps.iter().any(|cap| {
60	            cap.http_method.to_uppercase() == method_upper && path_matches(&cap.path_pattern, http_path)
61	        });
62	        if !matched {
63	            return Err(AppError::Forbidden(format!(
64	                "No matching API capability for {} {} on permission {}",
65	                http_method, http_path, permission_code
66	            )));
67	        }
68	    }
69	
70	    if perm.requires_approval {
71	        return Err(AppError::Forbidden(
72	            format!("Permission {} requires approval workflow", permission_code),
73	        ));
74	    }
75	
76	    Ok(build_context(claims, perm.id))
77	}
