79	/// Layers 1+2: resolve permission point and verify role binding.
80	fn resolve_layers_1_2(
81	    claims: &Claims,
82	    permission_code: &str,
83	    conn: &mut PgConnection,
84	) -> Result<PermissionPoint, AppError> {
85	    let perm: PermissionPoint = permission_points::table
86	        .filter(permission_points::code.eq(permission_code))
87	        .first(conn)
88	        .map_err(|_| AppError::Forbidden(format!("Unknown permission: {}", permission_code)))?;
89	
90	    let has_role_binding: bool = role_permissions::table
91	        .filter(role_permissions::role_id.eq(claims.role_id))
92	        .filter(role_permissions::permission_point_id.eq(perm.id))
93	        .count()
94	        .get_result::<i64>(conn)
95	        .map(|c| c > 0)
96	        .unwrap_or(false);
97	
98	    let has_delegation = claims.delegated_permissions.contains(&perm.id);
99	
100	    if !has_role_binding && !has_delegation {
101	        return Err(AppError::Forbidden(format!(
102	            "Missing permission: {}", permission_code
103	        )));
104	    }
105	
106	    Ok(perm)
107	}
