109	/// Matches a capability path_pattern against a concrete request path.
110	/// `*` matches a single segment; `**` at the end matches any trailing segments.
111	pub fn path_matches(pattern: &str, path: &str) -> bool {
112	    if pattern == path {
113	        return true;
114	    }
115	    let pat: Vec<&str> = pattern.split('/').filter(|s| !s.is_empty()).collect();
116	    let req: Vec<&str> = path.split('/').filter(|s| !s.is_empty()).collect();
117	
118	    if pat.last() == Some(&"**") {
119	        let prefix = &pat[..pat.len() - 1];
120	        if req.len() < prefix.len() {
121	            return false;
122	        }
123	        return prefix.iter().zip(req.iter()).all(|(p, r)| *p == "*" || p == r);
124	    }
125	
126	    if pat.len() != req.len() {
127	        return false;
128	    }
129	    pat.iter().zip(req.iter()).all(|(p, r)| *p == "*" || p == r)
130	}
