132	fn build_context(claims: &Claims, permission_point_id: Uuid) -> PermissionContext {
133	    PermissionContext {
134	        user_id: claims.sub,
135	        data_scope: claims.data_scope.clone(),
136	        scope_value: claims.scope_value.clone(),
137	        department: claims.department.clone(),
138	        location: claims.location.clone(),
139	        permission_point_id,
140	    }
141	}
