1	use crate::models::order::OrderStatus;
2	
3	/// Returns true if the state transition from `from` to `to` is valid.
4	pub fn valid_transition(from: &OrderStatus, to: &OrderStatus) -> bool {
5	    matches!(
6	        (from, to),
7	        (OrderStatus::Draft, OrderStatus::Open)
8	            | (OrderStatus::Open, OrderStatus::Tendering)
9	            | (OrderStatus::Tendering, OrderStatus::Paid)
10	            | (OrderStatus::Paid, OrderStatus::Closed)
11	            // Returns
12	            | (OrderStatus::Paid, OrderStatus::ReturnInitiated)
13	            | (OrderStatus::Closed, OrderStatus::ReturnInitiated)
14	            | (OrderStatus::ReturnInitiated, OrderStatus::Returned)
15	            // Reversals
16	            | (OrderStatus::Paid, OrderStatus::ReversalPending)
17	            | (OrderStatus::Closed, OrderStatus::ReversalPending)
18	            | (OrderStatus::ReversalPending, OrderStatus::Reversed)
19	    )
20	}
21	
22	/// Returns the permission code required for a given target status transition.
23	/// Returns None if the base `order.transition` permission is sufficient.
24	pub fn extra_permission_for_transition(to: &OrderStatus) -> Option<&'static str> {
25	    match to {
26	        OrderStatus::ReturnInitiated => Some("order.return"),
27	        OrderStatus::ReversalPending => Some("order.reverse"),
28	        OrderStatus::Reversed => Some("order.reverse"),
29	        _ => None,
30	    }
31	}
32	
33	#[cfg(test)]
34	mod tests {
35	    use super::*;
36	
37	    #[test]
38	    fn test_happy_path() {
39	        assert!(valid_transition(&OrderStatus::Draft, &OrderStatus::Open));
40	        assert!(valid_transition(&OrderStatus::Open, &OrderStatus::Tendering));
41	        assert!(valid_transition(&OrderStatus::Tendering, &OrderStatus::Paid));
42	        assert!(valid_transition(&OrderStatus::Paid, &OrderStatus::Closed));
43	    }
44	
45	    #[test]
46	    fn test_return_path() {
47	        assert!(valid_transition(&OrderStatus::Paid, &OrderStatus::ReturnInitiated));
48	        assert!(valid_transition(&OrderStatus::Closed, &OrderStatus::ReturnInitiated));
49	        assert!(valid_transition(&OrderStatus::ReturnInitiated, &OrderStatus::Returned));
50	    }
51	
52	    #[test]
53	    fn test_reversal_path() {
54	        assert!(valid_transition(&OrderStatus::Paid, &OrderStatus::ReversalPending));
55	        assert!(valid_transition(&OrderStatus::Closed, &OrderStatus::ReversalPending));
56	        assert!(valid_transition(&OrderStatus::ReversalPending, &OrderStatus::Reversed));
57	    }
58	
59	    #[test]
60	    fn test_invalid_transitions() {
61	        assert!(!valid_transition(&OrderStatus::Draft, &OrderStatus::Paid));
62	        assert!(!valid_transition(&OrderStatus::Closed, &OrderStatus::Open));
63	        assert!(!valid_transition(&OrderStatus::Reversed, &OrderStatus::Draft));
64	        assert!(!valid_transition(&OrderStatus::Returned, &OrderStatus::Paid));
65	    }
66	
67	    #[test]
68	    fn test_no_self_transitions() {
69	        assert!(!valid_transition(&OrderStatus::Draft, &OrderStatus::Draft));
70	        assert!(!valid_transition(&OrderStatus::Open, &OrderStatus::Open));
71	        assert!(!valid_transition(&OrderStatus::Paid, &OrderStatus::Paid));
72	    }
73	
74	    #[test]
75	    fn test_cannot_skip_states() {
76	        assert!(!valid_transition(&OrderStatus::Draft, &OrderStatus::Tendering));
77	        assert!(!valid_transition(&OrderStatus::Draft, &OrderStatus::Closed));
78	        assert!(!valid_transition(&OrderStatus::Open, &OrderStatus::Paid));
79	        assert!(!valid_transition(&OrderStatus::Open, &OrderStatus::Closed));
80	    }
81	
82	    #[test]
83	    fn test_terminal_states_have_no_exits() {
84	        let terminals = [OrderStatus::Reversed, OrderStatus::Returned];
85	        let all_states = [
86	            OrderStatus::Draft, OrderStatus::Open, OrderStatus::Tendering,
87	            OrderStatus::Paid, OrderStatus::Closed, OrderStatus::ReturnInitiated,
88	            OrderStatus::Returned, OrderStatus::ReversalPending, OrderStatus::Reversed,
89	        ];
90	        for terminal in &terminals {
91	            for target in &all_states {
92	                assert!(
93	                    !valid_transition(terminal, target),
94	                    "Terminal {:?} should not transition to {:?}", terminal, target
95	                );
96	            }
97	        }
98	    }
99	
100	    #[test]
101	    fn test_extra_permission_return() {
