3	use uuid::Uuid;
4	
5	#[derive(Debug, thiserror::Error)]
6	pub enum AppError {
7	    #[error("Unauthorized: {0}")]
8	    Unauthorized(String),
9	
10	    #[error("Forbidden: {0}")]
11	    Forbidden(String),
12	
13	    #[error("Not found: {0}")]
14	    NotFound(String),
15	
16	    #[error("Validation error: {0}")]
17	    Validation(String),
18	
19	    #[error("Conflict: {0}")]
20	    Conflict(String),
21	
22	    #[error("Account locked until {0}")]
23	    AccountLocked(String),
24	
25	    #[error("Approval required")]
26	    ApprovalRequired { request_id: Uuid },
27	
28	    #[error("Internal error")]
29	    Internal(String),
30	}
31	
32	#[derive(Serialize)]
33	struct ErrorBody {
34	    error: String,
35	    code: String,
36	    #[serde(skip_serializing_if = "Option::is_none")]
37	    approval_request_id: Option<Uuid>,
38	}
39	
40	impl ResponseError for AppError {
41	    fn error_response(&self) -> HttpResponse {
42	        match self {
43	            AppError::Unauthorized(msg) => HttpResponse::Unauthorized().json(ErrorBody {
44	                error: msg.clone(),
45	                code: "UNAUTHORIZED".into(),
46	                approval_request_id: None,
47	            }),
48	            AppError::Forbidden(msg) => HttpResponse::Forbidden().json(ErrorBody {
49	                error: msg.clone(),
50	                code: "FORBIDDEN".into(),
51	                approval_request_id: None,
52	            }),
53	            AppError::NotFound(msg) => HttpResponse::NotFound().json(ErrorBody {
54	                error: msg.clone(),
55	                code: "NOT_FOUND".into(),
56	                approval_request_id: None,
57	            }),
58	            AppError::Validation(msg) => HttpResponse::BadRequest().json(ErrorBody {
59	                error: msg.clone(),
60	                code: "VALIDATION_ERROR".into(),
61	                approval_request_id: None,
62	            }),
63	            AppError::Conflict(msg) => HttpResponse::Conflict().json(ErrorBody {
64	                error: msg.clone(),
65	                code: "CONFLICT".into(),
66	                approval_request_id: None,
67	            }),
68	            AppError::AccountLocked(until) => HttpResponse::TooManyRequests().json(ErrorBody {
69	                error: format!("Account locked until {}", until),
70	                code: "ACCOUNT_LOCKED".into(),
71	                approval_request_id: None,
72	            }),
73	            AppError::ApprovalRequired { request_id } => {
74	                HttpResponse::Accepted().json(ErrorBody {
75	                    error: "Action requires approval".into(),
76	                    code: "APPROVAL_REQUIRED".into(),
77	                    approval_request_id: Some(*request_id),
78	                })
79	            }
80	            AppError::Internal(msg) => {
81	                log::error!("Internal error: {}", msg);
82	                HttpResponse::InternalServerError().json(ErrorBody {
83	                    error: "Internal server error".into(),
84	                    code: "INTERNAL_ERROR".into(),
85	                    approval_request_id: None,
86	                })
87	            }
88	        }
89	    }
90	}
91	
92	impl From<diesel::result::Error> for AppError {
93	    fn from(e: diesel::result::Error) -> Self {
94	        match e {
95	            diesel::result::Error::NotFound => AppError::NotFound("Resource not found".into()),
96	            diesel::result::Error::DatabaseError(
97	                diesel::result::DatabaseErrorKind::UniqueViolation,
98	                info,
99	            ) => AppError::Conflict(
100	                info.message().to_string(),
101	            ),
102	            _ => AppError::Internal(e.to_string()),
103	        }
104	    }
105	}
106	
107	/// Helper to convert pool errors to AppError.
108	pub fn pool_err(e: impl std::fmt::Display) -> AppError {
109	    AppError::Internal(format!("Pool error: {}", e))
110	}
