393	            "type": "order_reversal",
394	            "order_id": order_id,
395	            "order_number": order.order_number,
396	            "idempotency_key": body.idempotency_key,
397	            "is_late_reversal": is_late,
398	            "note": body.notes,
399	            "requested_by": auth.0.sub,
400	        });
401	
402	        let approval: ApprovalRequest = diesel::insert_into(approval_requests::table)
403	            .values(&NewApprovalRequest {
404	                permission_point_id: perm_id,
405	                requester_user_id: auth.0.sub,
406	                payload,
407	            })
408	            .returning(ApprovalRequest::as_returning())
409	            .get_result(conn)?;
410	
411	        // Mark order as ReversalPending (no ledger changes)
412	        diesel::update(orders::table.find(order_id))
413	            .set((
414	                orders::status.eq(OrderStatus::ReversalPending),
415	                orders::notes.eq(body.notes.as_deref()),
416	                orders::updated_at.eq(Utc::now()),
417	            ))
418	            .execute(conn)?;
419	
420	        let response = serde_json::json!({
421	            "message": "Reversal requires approval before financial mutation",
422	            "approval_request_id": approval.id,
423	            "order_id": order_id,
424	            "status": "reversal_pending",
425	        });
426	
427	        Ok((approval.id, response))
428	    })?;
429	
430	    let json = serde_json::to_value(&response).unwrap();
431	    finalize_idempotency(body.idempotency_key, order_id, 202, &json, &mut conn)?;
432	
433	    Ok(HttpResponse::Accepted().json(response))
434	}
